mapper.select:
WITH AUTH_PROJECT AS ( SELECT p.project_code, p.project_name FROM projects p WHERE 1=1
AND p.project_code = #{projectCode}
AND p.status = #{projectStatusName}
AND EXISTS ( SELECT 1 FROM VW_USER_AUTH vua WHERE vua.user_code = #{userCode} AND vua.project_code = p.project_code AND ( (vua.admin_ck = 'Y' AND vua.status IN ('OD1','OD3')) OR (NVL(vua.admin_ck,'N') = 'N' AND vua.status = 'OD1') ) ) ),
FOLDER_TREE AS ( SELECT f.folder_code, f.project_code, f.folder_name, LEVEL AS folder_depth, SYS_CONNECT_BY_PATH(f.folder_name, '/') AS folder_path, SYS_CONNECT_BY_PATH(LPAD(f.folder_code, 10, '0'), '/') AS sort_path FROM documents_folders f START WITH f.header_folder_code IS NULL CONNECT BY PRIOR f.folder_code = f.header_folder_code )
SELECT * FROM (
/* 1️⃣ 프로젝트 : 파일 검색 조건에 맞는 파일이 있는 프로젝트만 */ SELECT NULL AS file_code, NULL AS original_name, NULL AS size_bytes, NULL AS uploaded_at, NULL AS mime_type, NULL AS folder_code, ap.project_code, ap.project_name, NULL AS uploaderName, NULL AS folder_path, 0 AS folder_depth, NULL AS folder_name, TO_CHAR(ap.project_code, 'FM0000000000') AS sort_path, 'PROJECT' AS row_type, NULL AS createdCode FROM AUTH_PROJECT ap WHERE 1=1
AND ap.project_code IN ( SELECT project_code FROM documents_attachments da WHERE 1=1 AND da.original_name LIKE '%' || #{fileName} || '%' AND (LOWER(da.mime_type) LIKE '%' || LOWER(#{fileType}) || '%' OR LOWER(da.original_name) LIKE '%.' || LOWER(#{fileType})) AND da.user_code = #{createdCode} )
UNION ALL
/* 2️⃣ 폴더 : 파일 검색 조건에 맞는 파일을 가진 폴더 + 그 폴더의 모든 상위 부모 */ SELECT NULL, NULL, NULL, NULL, NULL, ft.folder_code, ft.project_code, ap.project_name, NULL, ft.folder_path, ft.folder_depth, ft.folder_name, TO_CHAR(ft.project_code, 'FM0000000000') || ft.sort_path, 'FOLDER', NULL AS createdCode FROM FOLDER_TREE ft JOIN AUTH_PROJECT ap ON ft.project_code = ap.project_code WHERE 1=1
AND ft.folder_code IN ( SELECT folder_code FROM documents_folders START WITH folder_code = #{folderCode} CONNECT BY PRIOR folder_code = header_folder_code UNION SELECT folder_code FROM documents_folders START WITH folder_code = #{folderCode} CONNECT BY folder_code = PRIOR header_folder_code )
AND ft.folder_code IN ( SELECT folder_code FROM documents_folders START WITH folder_code IN ( SELECT da.folder_code FROM documents_attachments da LEFT JOIN users u ON da.user_code = u.user_code WHERE 1=1 AND da.original_name LIKE '%' || #{fileName} || '%'
AND (LOWER(da.mime_type) LIKE '%spreadsheet%' OR LOWER(da.original_name) LIKE '%.xls%') AND LOWER(da.mime_type) LIKE 'image/%' AND (LOWER(da.mime_type) LIKE '%' || LOWER(#{fileType}) || '%' OR LOWER(da.original_name) LIKE '%.' || LOWER(#{fileType}))
AND da.user_code = #{createdCode}
AND da.uploaded_at >= TO_DATE(#{createdFrom}, 'YYYY-MM-DD') AND da.uploaded_at <= TO_DATE(#{createdTo}, 'YYYY-MM-DD') + 0.99999 ) CONNECT BY folder_code = PRIOR header_folder_code )
UNION ALL
/* 3️⃣ 파일 : 실제 조건에 맞는 파일만 */ SELECT da.file_code, da.original_name, da.size_bytes, da.uploaded_at, da.mime_type, da.folder_code, da.project_code, ap.project_name, u.name AS uploaderName, ft.folder_path, ft.folder_depth, ft.folder_name, TO_CHAR(da.project_code, 'FM0000000000') || ft.sort_path || '/' || LPAD(da.file_code, 10, '0'), 'FILE', da.user_code AS createdCode FROM documents_attachments da JOIN AUTH_PROJECT ap ON da.project_code = ap.project_code LEFT JOIN users u ON da.user_code = u.user_code LEFT JOIN FOLDER_TREE ft ON da.folder_code = ft.folder_code WHERE 1=1 AND da.original_name LIKE '%' || #{fileName} || '%' AND u.name LIKE '%' || #{uploaderName} || '%' AND da.uploaded_at >= TO_DATE(#{createdFrom}, 'YYYY-MM-DD') AND da.uploaded_at <= TO_DATE(#{createdTo}, 'YYYY-MM-DD') + 0.99999
AND (LOWER(da.mime_type) LIKE '%spreadsheet%' OR LOWER(da.original_name) LIKE '%.xls%')
AND (LOWER(da.mime_type) LIKE '%word%' OR LOWER(da.original_name) LIKE '%.doc%')
AND LOWER(da.mime_type) LIKE 'image/%'
AND (LOWER(da.mime_type) LIKE '%presentation%' OR LOWER(da.original_name) LIKE '%.ppt%')
AND (LOWER(da.mime_type) LIKE '%' || LOWER(#{fileType}) || '%' OR LOWER(da.original_name) LIKE '%.' || LOWER(#{fileType}))
AND da.folder_code IN ( SELECT folder_code FROM documents_folders START WITH folder_code = #{folderCode} CONNECT BY PRIOR folder_code = header_folder_code )
AND da.user_code = #{createdCode}
) t ORDER BY t.sort_path, DECODE(t.row_type, 'PROJECT', 1, 'FOLDER', 2, 'FILE', 3)

SELECT COUNT(*)
FROM documents_folders
WHERE header_folder_code = #{folderCode}
